package org.joda.time.field;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.joda.time.field.steps"
)
public class CucumberTest {
}

package org.joda.time.field.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.joda.time.DateTimeFieldType;
import org.joda.time.Partial;
import static org.junit.Assert.fail;
import static org.junit.Assert.assertTrue;

public class StepDefs {
    private DateTimeFieldType[] types;
    private int[] values;
    private Exception exception;

    @Given("^the field types are \\[(.*)\\]$")
    public void the_field_types_are(String typesStr) {
        String[] typeNames = typesStr.split(", ");
        types = new DateTimeFieldType[typeNames.length];
        for (int i = 0; i < typeNames.length; i++) {
             String typeName = typeNames[i].trim();
             if ("year".equals(typeName)) types[i] = DateTimeFieldType.year();
             else if ("era".equals(typeName)) types[i] = DateTimeFieldType.era();
             else if ("monthOfYear".equals(typeName)) types[i] = DateTimeFieldType.monthOfYear();
             else if ("dayOfMonth".equals(typeName)) types[i] = DateTimeFieldType.dayOfMonth();
             else throw new IllegalArgumentException("Unknown field type: " + typeName);
        }
    }

    @Given("^the values are \\[(.*)\\]$")
    public void the_values_are(String valuesStr) {
        String[] valueStrs = valuesStr.split(", ");
        values = new int[valueStrs.length];
        for (int i = 0; i < valueStrs.length; i++) {
            values[i] = Integer.parseInt(valueStrs[i].trim());
        }
    }

    @When("I construct a Partial with these types and values")
    public void i_construct_a_partial_with_these_types_and_values() {
        try {
            new Partial(types, values);
        } catch (Exception e) {
            exception = e;
        }
    }

    @Then("the construction should fail with an IllegalArgumentException")
    public void the_construction_should_fail_with_an_illegal_argument_exception() {
        if (exception == null) {
            fail("Expected IllegalArgumentException but no exception was thrown");
        }
        assertTrue("Expected IllegalArgumentException but got " + exception.getClass().getName(),
                exception instanceof IllegalArgumentException);
    }

    @Then("the exception message should indicate that the types must be in order largest-smallest")
    public void the_exception_message_should_indicate_that_the_types_must_be_in_order_largest_smallest() {
         String msg = exception.getMessage();
         assertTrue("Message was: " + msg, msg != null && msg.contains("must be in order largest-smallest"));
    }
}
